  ('elementary-7fec267e-moex-00123', 'elementary-7fec267e', 'elementary-7fec267e-moex-114-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '住所地在臺北之甲，與住所地在桃園之乙及住所地在新竹之丙，三人相約在臺中見面。言談間因細故發生 爭吵，甲遭乙與丙共同毆傷。甲欲依民法侵權行為規定，將乙、丙列為共同被告，請求損害賠償，依民事 訴訟法規定，由何法院管轄？', '["臺灣臺北地方法院", "臺灣桃園地方法院", "臺灣新竹地方法院", "臺灣臺中地方法院"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:57+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
